#include <bits/stdc++.h>
using namespace std;
struct Node{
    int val,id;
}l[400005];
bool cmp(Node x,Node y){
    return x.val<y.val;
}
const int mod=1e9+7;
int n,a[200005],m[200005];
long long mi[200005];
bool use[200005];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&m[i]);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        l[2*i-1]={a[i]-1,i};
        l[2*i]={m[i]-a[i],i};
    }
    mi[0]=1;
    for(int i=1;i<=2*n;i++)
        mi[i]=mi[i-1]*2%mod;
    sort(l+1,l+2*n+1,cmp);
    long long ans=1;
    for(int i=1;i<=2*n;i++)
        if(use[l[i].id]){
            ans+=mi[n-i+1]*l[i].val,ans%=mod;
            break;
        }else{
            use[l[i].id]=1;
            ans+=mi[n-i]*l[i].val,ans%=mod;
        }
    printf("%lld",ans);
    return 0;
}
